Category: Waveform

Command: WLISt:WAVeform:NORMalize "{name}",{type}
Description: Normalize waveform data
Category: Waveform

Command: CLOCk:ECLock:DIVider {divider}
Description: Set external clock divider rate (power of 2)
Category: Clock

Command: CLOCk:ECLock:FREQuency {freq}
Description: Set expected external clock frequency (6.25-12.5 GHz)
Category: Clock

Command: CLOCk:ECLock:MULTiplier {mult}
Description: Set external clock multiplier (1, 2, or 4)
Category: Clock

Command: CLOCk:EREFerence:DIVider {divider}
Description: Set external reference divider rate
Category: Clock

Command: CLOCk:EREFerence:FREQuency {freq}
Description: Set expected external reference frequency (35-250 MHz)
Category: Clock

Command: CLOCk:EREFerence:MULTiplier {mult}
Description: Set external reference multiplier rate
Category: Clock

Command: CLOCk:JITTer {state}
Description: Enable/disable jitter reduction for clock
Category: Clock

Command: CLOCk:OUTPut:STATe {state}
Description: Enable/disable clock output
Category: Clock

Command: CLOCk:PHASe:ADJust:DEGRees {degrees}
Description: Set clock phase adjustment in degrees (-10800 to 10800)
Category: Clock

Command: CLOCk:PHASe:ADJust:TIMe {time}
Description: Set clock phase adjustment in picoseconds
Category: Clock

Command: CLOCk:SOUT:STATe {state}
Description: Enable/disable Sync Clock Out output
Category: Clock

Command: AWGControl:RMODe {mode}
Description: Set the run mode
Category: Sequence

Command: SLISt:SEQuence:NEW "{name}",{steps},{tracks}
Description: Create a new sequence
Category: Sequence

Command: SLISt:SEQuence:STEP{step}:RCOunt "{seq}",{count}
Description: Set repeat count for sequence step
Category: Sequence

Command: SLISt:SEQuence:STEP{step}:GOTO "{seq}",{target}
Description: Set goto target for sequence step
Category: Sequence

Command: SOURce{ch}:MARKer{m}:STATe {state}
Description: Enable/disable marker output
Category: Marker

Command: SOURce{ch}:MARKer{m}:DELay {delay}
Description: Set marker delay in seconds
Category: Marker

Command: SOURce{ch}:MARKer{m}:VOLTage:LEVel:IMMediate:HIGH {level}
Description: Set marker high voltage level
Category: Marker

Command: SOURce{ch}:MARKer{m}:VOLTage:LEVel:IMMediate:LOW {level}
Description: Set marker low voltage level
Category: Marker

Command: TRIGger:SOURce {source}
Description: Set trigger source
Category: Trigger

Command: TRIGger:LEVel {level}
Description: Set external trigger level
Category: Trigger

Command: TRIGger:SLOPe {slope}
Description: Set trigger slope
Category: Trigger

Command: TRIGger:IMPedance {impedance}
Description: Set external trigger impedance
Category: Trigger

Command: TRIGger:MODE {mode}
Description: Set trigger wait mode
Category: Trigger

Command: CALibration:CATalog? {subsystem},{area}
Description: List calibration subsystems, areas, or procedures
Category: Calibration

Command: PULSe:COMPile:CASSign {state}
Description: Set compilation type (compile only or compile and assign)
Category: Pulse_Plugin

Command: PULSe:COMPile:OSAMpling {rate}
Description: Set oversampling rate for pulse compilation (1-1000)
Category: Pulse_Plugin

Command: PULSe:COMPile:OVERwrite {state}
Description: Enable/disable overwriting existing waveforms during compilation
Category: Pulse_Plugin

Command: PULSe:COMPile:PLAY {state}
Description: Enable/disable play after assign
Category: Pulse_Plugin

Command: PULSe:COMPile:SEQuence {state}
Description: Enable/disable creating sequence after compilation
Category: Pulse_Plugin

Command: PULSe:COMPile:SRATe {rate}
Description: Set sampling rate for pulse compilation
Category: Pulse_Plugin

Command: PULSe:COMPile:SRATe:AUTO {state}
Description: Enable/disable automatic sample rate calculation
Category: Pulse_Plugin

Command: PULSe:FRAMe:DELete {index}
Description: Delete pulse definition at specified index (1-100)
Category: Pulse_Plugin

Command: PULSe:FRAMe:DTIMe {time}
Description: Set dead time for current frame (0-1 seconds)
Category: Pulse_Plugin

Command: PULSe:FRAMe:NPULse {count}
Description: Set number of pulses in current frame (1-10000)
Category: Pulse_Plugin

Command: PULSe:FRAMe:SELect {index}
Description: Select pulse definition index for editing (1-100)
Category: Pulse_Plugin

Command: PULSe:FRAMe:PSETup:FTIMe:PERCentage {type}
Description: Set fall time percentage type
Category: Pulse_Plugin

Command: PULSe:FRAMe:PSETup:FTIMe:VALue {time}
Description: Set fall time value for pulse
Category: Pulse_Plugin

Command: PULSe:FRAMe:PSETup:OTIMe {time}
Description: Set off time value for frame (0-1 seconds)
Category: Pulse_Plugin

Command: PULSe:FRAMe:PSETup:PRF {freq}
Description: Set pulse repeat frequency for frame
Category: Pulse_Plugin

Command: PULSe:FRAMe:PSETup:PRI {interval}
Description: Set pulse repeat interval for frame
Category: Pulse_Plugin

Command: PULSe:FRAMe:PSETup:RTIMe:PERCentage {type}
Description: Set rise time percentage type
Category: Pulse_Plugin

Command: PULSe:FRAMe:PSETup:RTIMe:VALue {time}
Description: Set rise time value for pulse
Category: Pulse_Plugin

Command: PULSe:FRAMe:PSETup:SHAPe {shape}
Description: Set pulse shape (rectangular or trapezoidal)
Category: Pulse_Plugin

Command: PULSe:FRAMe:PSETup:WIDTh:PERCentage {type}
Description: Set pulse width percentage type
Category: Pulse_Plugin

Command: PULSe:FRAMe:PSETup:WIDTh:VALue {width}
Description: Set pulse width value (200ps-1s)
Category: Pulse_Plugin

Command: PULSe:PTRain:ADD {name}
Description: Create and add pulse train to list (max 10 trains)
Category: Pulse_Plugin

Command: PULSe:PTRain:AMPLitude {amplitude}
Description: Set peak-to-peak amplitude (25mV-1.5V)
Category: Pulse_Plugin

Command: PULSe:PTRain:CHANnel {channel}
Description: Set channel for pulse train waveform/sequence
Category: Pulse_Plugin

Command: PULSe:PTRain:DELete {name}
Description: Delete specified pulse train from list
Category: Pulse_Plugin

Command: PULSe:PTRain:REName {name}
Description: Rename current selected pulse train
Category: Pulse_Plugin

Command: PULSe:PTRain:SELect {name}
Description: Select pulse train by name
Category: Pulse_Plugin

Command: LVS:COMPile:CASSign {state}
Description: Set video compilation type
Category: Video_Plugin

Command: LVS:COMPile:CHANnel {signal},{channel}
Description: Set channel for video signal (Clock/DL0-4/IClock/IDL0-4)
